async (params, browser) => {
  // Open reviews page
  await browser.open(`https://www.imdb.com/title/${params.title_id}/reviews/`)

  // Wait for reviews
  await browser.waitForSelector('article.user-review-item, [data-testid=\'review-card\'], [class*=\'review\'], .lister-item, .imdb-user-review', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll through reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('article.user-review-item, [data-testid="review-card"], .lister-item, .imdb-user-review, [class*="review-container"], [class*="UserReview"]'); for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const titleEl = el.querySelector('a.title, [class*="title"] a, h3 a, h3, .ipc-title__text'); const ratingEl = el.querySelector('.ipc-rating-star--rating, [class*="rating"] span, [class*="ipl-ratings-bar"] span, [class*="score"]'); const authorEl = el.querySelector('[class*="display-name"], [class*="author"] a, a[href*="/user/"]'); const dateEl = el.querySelector('[class*="review-date"], [class*="date"], time'); const contentEl = el.querySelector('[class*="content"] div, [class*="text"], [class*="review-body"], .ipc-html-content-inner-div'); const helpfulEl = el.querySelector('[class*="actions"], [class*="helpful"]'); reviews.push({ title: titleEl ? titleEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', author: authorEl ? authorEl.textContent.trim() : '', date: dateEl ? dateEl.textContent.trim() : '', content: contentEl ? contentEl.textContent.trim().substring(0, 1000) : '', helpful: helpfulEl ? helpfulEl.textContent.trim() : '' }); } const overallRatingEl = document.querySelector('[data-testid="hero-rating-bar__aggregate-rating__score"] span, .ipc-rating-star--rating'); const titleIdMatch = window.location.pathname.match(/\/title\/(tt\d+)/); return { title_id: titleIdMatch ? titleIdMatch[1] : '', overall_rating: overallRatingEl ? overallRatingEl.textContent.trim() : '', review_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
